import { r as getContainers } from "../../../chunks/docker.js";
//#region src/routes/containers/+page.server.ts
var load = async () => {
	return { containers: (await getContainers(true)).map((c) => ({
		id: c.Id,
		name: c.Names[0].replace(/^\//, ""),
		state: c.State,
		status: c.Status,
		image: c.Image,
		ports: c.Ports,
		created: c.Created
	})) };
};
//#endregion
export { load };
